    code: "#include <vector>\n#include <queue>\nusing namespace std;\n\nclass Solution {\npublic:\n    int lastStoneWeight(vector<int>& stones) {\n        // Max-heap: largest element is always on top\n        priority_queue<int> pq(stones.begin(), stones.end());\n\n        while (pq.size() > 1) {\n            int heaviest = pq.top(); pq.pop();\n            int second   = pq.top(); pq.pop();\n\n            // Only push the remainder when the stones differ\n            if (heaviest != second)\n                pq.push(heaviest - second);\n        }\n\n        return pq.empty() ? 0 : pq.top();\n    }\n};\n",
