    code: "#include <vector>\n#include <algorithm>\n#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    int maxProfit(vector<int>& prices) {\n        // buy1: max profit after first buy  (negative cost)\n        // sell1: max profit after first sell\n        // buy2: max profit after second buy (sell1 minus new cost)\n        // sell2: max profit after second sell — the answer\n        int buy1 = INT_MIN, sell1 = 0;\n        int buy2 = INT_MIN, sell2 = 0;\n\n        for (int price : prices) {\n            buy1  = max(buy1,        -price);       // pay price for 1st share\n            sell1 = max(sell1, buy1  + price);      // sell 1st share\n            buy2  = max(buy2,  sell1 - price);      // pay price for 2nd share\n            sell2 = max(sell2, buy2  + price);      // sell 2nd share\n        }\n\n        return sell2;  // 0 if no profitable transaction exists\n    }\n};\n",
