    code: "#include <string>\n#include <vector>\n#include <unordered_set>\n#include <queue>\nusing namespace std;\n\nclass Solution {\npublic:\n    int ladderLength(string beginWord, string endWord, vector<string>& wordList) {\n        // Build a hash set for O(1) membership checks; also serves as visited tracker.\n        unordered_set<string> available(wordList.begin(), wordList.end());\n\n        // If the target isn't in the dictionary, transformation is impossible.\n        if (!available.count(endWord)) return 0;\n\n        queue<string> bfsQueue;\n        bfsQueue.push(beginWord);\n        int steps = 1; // beginWord itself counts as step 1\n\n        while (!bfsQueue.empty()) {\n            int levelSize = static_cast<int>(bfsQueue.size());\n\n            // Process all nodes at the current BFS depth.\n            for (int i = 0; i < levelSize; ++i) {\n                string word = bfsQueue.front();\n                bfsQueue.pop();\n\n                // Try mutating every character position.\n                for (int pos = 0; pos < static_cast<int>(word.size()); ++pos) {\n                    char original = word[pos];\n                    for (char c = 'a'; c <= 'z'; ++c) {\n                        if (c == original) continue;\n                        word[pos] = c;\n                        if (word == endWord) return steps + 1;\n                        if (available.count(word)) {\n                            // Mark visited by removing from the set before enqueuing.\n                            available.erase(word);\n                            bfsQueue.push(word);\n                        }\n                        word[pos] = original; // restore\n                    }\n                }\n            }\n\n            ++steps;\n        }\n\n        return 0; // endWord unreachable\n    }\n};\n",
