    code: "#include <unordered_map>\n#include <vector>\nusing namespace std;\n\n// Node definition provided by the judge\nclass Node {\npublic:\n    int val;\n    vector<Node*> neighbors;\n    Node() : val(0), neighbors({}) {}\n    Node(int _val) : val(_val), neighbors({}) {}\n    Node(int _val, vector<Node*> _neighbors) : val(_val), neighbors(_neighbors) {}\n};\n\nclass Solution {\npublic:\n    Node* cloneGraph(Node* node) {\n        if (!node) return nullptr;\n\n        // If already cloned, return the cached copy to handle cycles\n        auto it = visited.find(node);\n        if (it != visited.end()) return it->second;\n\n        // Create the clone and register it before visiting neighbors\n        Node* clone = new Node(node->val);\n        visited[node] = clone;\n\n        // Recursively clone each neighbor\n        for (Node* neighbor : node->neighbors)\n            clone->neighbors.push_back(cloneGraph(neighbor));\n\n        return clone;\n    }\n\nprivate:\n    unordered_map<Node*, Node*> visited; // original -> clone\n};",
