    code: "#include <cstddef>\nusing namespace std;\n\n// Node definition as given by LeetCode\nclass Node {\npublic:\n    int val;\n    Node* next;\n    Node* random;\n    Node(int _val) : val(_val), next(nullptr), random(nullptr) {}\n};\n\nclass Solution {\npublic:\n    Node* copyRandomList(Node* head) {\n        if (!head) return nullptr;\n\n        // Phase 1: interleave clones.\n        // Transform: A -> B -> C  into  A -> A' -> B -> B' -> C -> C'\n        Node* cur = head;\n        while (cur) {\n            Node* clone = new Node(cur->val);\n            clone->next = cur->next;\n            cur->next   = clone;\n            cur         = clone->next;   // advance to the original next\n        }\n\n        // Phase 2: assign random pointers to clones.\n        // cur->next is the clone of cur; cur->random->next is the clone of random.\n        cur = head;\n        while (cur) {\n            if (cur->random)\n                cur->next->random = cur->random->next;\n            cur = cur->next->next;       // skip over clone to next original\n        }\n\n        // Phase 3: separate the interleaved list into original and clone lists.\n        Node dummy(0);\n        Node* tail = &dummy;\n        cur = head;\n        while (cur) {\n            Node* clone = cur->next;\n            tail->next  = clone;\n            tail        = clone;\n\n            cur->next   = clone->next;   // restore original list\n            cur         = cur->next;\n        }\n\n        return dummy.next;\n    }\n};\n",
