    code: "#include <cstddef>\nusing namespace std;\n\n// Definition for singly-linked list.\nstruct ListNode {\n    int val;\n    ListNode *next;\n    ListNode() : val(0), next(nullptr) {}\n    ListNode(int x) : val(x), next(nullptr) {}\n    ListNode(int x, ListNode *next) : val(x), next(next) {}\n};\n\nclass Solution {\npublic:\n    void reorderList(ListNode* head) {\n        if (!head || !head->next) return;\n\n        // --- Phase 1: find the end of the first half ---\n        // When the loop exits, `slow` sits at the last node of the first half.\n        ListNode* slow = head;\n        ListNode* fast = head->next;\n        while (fast && fast->next) {\n            slow = slow->next;\n            fast = fast->next->next;\n        }\n\n        // --- Phase 2: reverse the second half in-place ---\n        ListNode* second = slow->next;\n        slow->next = nullptr;   // detach first half from second\n\n        ListNode* prev = nullptr;\n        while (second) {\n            ListNode* nxt = second->next;\n            second->next = prev;\n            prev = second;\n            second = nxt;\n        }\n        // `prev` is now the head of the reversed second half\n\n        // --- Phase 3: interleave first half with reversed second half ---\n        ListNode* p1 = head;\n        ListNode* p2 = prev;\n        while (p2) {                    // second half is always <= first half length\n            ListNode* n1 = p1->next;\n            ListNode* n2 = p2->next;\n            p1->next = p2;\n            p2->next = n1;\n            p1 = n1;\n            p2 = n2;\n        }\n    }\n};\n",
