    code: "#include <stack>\nusing namespace std;\n\nclass MinStack {\n    stack<int> main_;   // holds every pushed value\n    stack<int> mins_;   // top is always the current minimum\n\npublic:\n    MinStack() {}\n\n    void push(int val) {\n        main_.push(val);\n        // Push onto the min-tracker when empty or val is a new (or tied) minimum.\n        // Tracking equal values ensures correctness when the current minimum is\n        // popped while a duplicate of it still exists in the stack.\n        if (mins_.empty() || val <= mins_.top()) {\n            mins_.push(val);\n        }\n    }\n\n    void pop() {\n        // If the element being removed is the current minimum, retire it from\n        // the min-tracker so the next-smallest value surfaces at the top.\n        if (main_.top() == mins_.top()) {\n            mins_.pop();\n        }\n        main_.pop();\n    }\n\n    int top() {\n        return main_.top();\n    }\n\n    int getMin() {\n        return mins_.top();\n    }\n};\n\n/**\n * Your MinStack object will be instantiated and called as such:\n * MinStack* obj = new MinStack();\n * obj->push(val);\n * obj->pop();\n * int param_3 = obj->top();\n * int param_4 = obj->getMin();\n */\n",
