    code: "#include <vector>\n#include <algorithm>\nusing namespace std;\n\nclass Solution {\npublic:\n    int maxProfit(int k, vector<int>& prices) {\n        int n = prices.size();\n        if (n == 0 || k == 0) return 0;\n\n        // buy[j]  = best portfolio value after holding a share, having used j-1 sells\n        // sell[j] = best portfolio value after completing exactly j full round-trips\n        vector<int> buy(k + 1, INT_MIN / 2); // initialise to -infinity\n        vector<int> sell(k + 1, 0);          // 0 transactions, 0 profit\n\n        for (int price : prices) {\n            for (int j = 1; j <= k; j++) {\n                buy[j]  = max(buy[j],  sell[j - 1] - price); // open j-th buy\n                sell[j] = max(sell[j], buy[j]      + price); // close j-th sell\n            }\n        }\n\n        return sell[k]; // max profit with at most k transactions\n    }\n};\n",
