    code: "#include <string>\n#include <array>\nusing namespace std;\n\nstruct TrieNode {\n    array<TrieNode*, 26> children{};  // zero-initialized to nullptr\n    bool isEnd = false;\n};\n\nclass Trie {\npublic:\n    Trie() : root(new TrieNode()) {}\n\n    // Insert all characters, creating nodes as needed; mark terminal.\n    void insert(const string& word) {\n        TrieNode* cur = root;\n        for (char c : word) {\n            int idx = c - 'a';\n            if (!cur->children[idx])\n                cur->children[idx] = new TrieNode();\n            cur = cur->children[idx];\n        }\n        cur->isEnd = true;\n    }\n\n    // Return true iff word was previously inserted in full.\n    bool search(const string& word) {\n        TrieNode* node = traverse(word);\n        return node && node->isEnd;\n    }\n\n    // Return true iff any inserted word starts with prefix.\n    bool startsWith(const string& prefix) {\n        return traverse(prefix) != nullptr;\n    }\n\nprivate:\n    TrieNode* root;\n\n    // Walk the trie following the characters of s; return the final node or nullptr.\n    TrieNode* traverse(const string& s) {\n        TrieNode* cur = root;\n        for (char c : s) {\n            cur = cur->children[c - 'a'];\n            if (!cur) return nullptr;\n        }\n        return cur;\n    }\n};\n\n/**\n * Your Trie object will be instantiated and called as such:\n * Trie* obj = new Trie();\n * obj->insert(word);\n * bool param_2 = obj->search(word);\n * bool param_3 = obj->startsWith(prefix);\n */\n",
