    code: "\n#include <string>\n#include <array>\nusing namespace std;\n\n// Trie node: 26 children (a–z) + end-of-word marker\nstruct TrieNode {\n    array<TrieNode*, 26> ch{};\n    bool isEnd = false;\n    ~TrieNode() { for (auto* c : ch) delete c; }\n};\n\nclass WordDictionary {\npublic:\n    WordDictionary() : root(new TrieNode()) {}\n    ~WordDictionary() { delete root; }\n\n    // Insert word into the trie, one character at a time.\n    void addWord(string word) {\n        TrieNode* cur = root;\n        for (char c : word) {\n            int idx = c - 'a';\n            if (!cur->ch[idx])\n                cur->ch[idx] = new TrieNode();\n            cur = cur->ch[idx];\n        }\n        cur->isEnd = true;\n    }\n\n    // Return true if word (possibly containing '.') exists in the dictionary.\n    bool search(string word) {\n        return dfs(root, word, 0);\n    }\n\nprivate:\n    TrieNode* root;\n\n    // DFS through the trie matching word[pos..] from node cur.\n    bool dfs(TrieNode* cur, const string& word, int pos) {\n        if (pos == (int)word.size())\n            return cur->isEnd;\n\n        char c = word[pos];\n        if (c == '.') {\n            // Wildcard: try every existing child.\n            for (TrieNode* child : cur->ch)\n                if (child && dfs(child, word, pos + 1))\n                    return true;\n            return false;\n        }\n\n        // Literal character: follow exactly one child.\n        TrieNode* child = cur->ch[c - 'a'];\n        return child && dfs(child, word, pos + 1);\n    }\n};\n\n/**\n * WordDictionary* obj = new WordDictionary();\n * obj->addWord(word);\n * bool found = obj->search(word);\n */\n",
