    code: "#include <algorithm>  // std::swap\nusing namespace std;\n\n// Definition for a binary tree node.\nstruct TreeNode {\n    int val;\n    TreeNode *left;\n    TreeNode *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}\n};\n\nclass Solution {\npublic:\n    TreeNode* invertTree(TreeNode* root) {\n        if (!root) return nullptr;           // base case: empty subtree\n\n        // Recursively invert both subtrees first (post-order),\n        // then mirror the children of the current node.\n        invertTree(root->left);\n        invertTree(root->right);\n        swap(root->left, root->right);       // mirror at this node\n\n        return root;\n    }\n};",
