    code: "#include <vector>\n#include <queue>\n#include <algorithm>\n\nusing namespace std;\n\nclass Solution {\npublic:\n    int minMeetingRooms(vector<vector<int>>& intervals) {\n        // Sort meetings by start time\n        sort(intervals.begin(), intervals.end());\n\n        // Min-heap storing end times of ongoing meetings\n        priority_queue<int, vector<int>, greater<int>> minHeap;\n\n        for (const auto& interval : intervals) {\n            int start = interval[0], end = interval[1];\n            // If the earliest-ending room is free, reuse it\n            if (!minHeap.empty() && minHeap.top() <= start) {\n                minHeap.pop();\n            }\n            // Assign this meeting to a room (new or reused)\n            minHeap.push(end);\n        }\n\n        // Each element in the heap represents an occupied room\n        return static_cast<int>(minHeap.size());\n    }\n};\n",
