    routeSlug: "307-range-sum-query-mutable",
    summary: "Given an integer array and a series of point-update and range-sum-query operations, build a data structure that supports updating a single element and returning the sum of elements over any subarray — both in sub-linear time.",
    approach: "- Use a **Fenwick Tree (Binary Indexed Tree)**, a compact array where each index stores a partial sum covering a range determined by its lowest set bit.\n- **Build** in O(n log n) by calling the point-update path for each element.\n- **Update** a single index by walking up the tree (add `i & -i` at each step), propagating the delta in O(log n).\n- **Prefix sum** queries walk down the tree (subtract `i & -i`) to accumulate partial sums; `sumRange(l, r)` is just `prefix(r+1) - prefix(l)`.",
    code: "#include <vector>\nusing namespace std;\n\nclass NumArray {\npublic:\n    NumArray(vector<int>& nums) : n(nums.size()), bit(nums.size() + 1, 0), orig(nums) {\n        // Build BIT by treating each element as a point update\n        for (int i = 0; i < n; ++i)\n            add(i + 1, nums[i]);\n    }\n\n    // Point update: set nums[index] to val\n    void update(int index, int val) {\n        int delta = val - orig[index];\n        orig[index] = val;\n        add(index + 1, delta);  // BIT is 1-indexed\n    }\n\n    // Range sum query [left, right] (0-indexed, inclusive)\n    int sumRange(int left, int right) {\n        return prefix(right + 1) - prefix(left);\n    }\n\nprivate:\n    int n;\n    vector<int> bit;   // 1-indexed Fenwick tree\n    vector<int> orig;  // mirror of the original array to compute deltas on update\n\n    // Add delta to 1-indexed position i and all ancestors\n    void add(int i, int delta) {\n        for (; i <= n; i += i & -i)\n            bit[i] += delta;\n    }\n\n    // Sum of elements [1..i] in 1-indexed BIT\n    int prefix(int i) {\n        int s = 0;\n        for (; i > 0; i -= i & -i)\n            s += bit[i];\n        return s;\n    }\n};\n",
