    routeSlug: "4-median-of-two-sorted-arrays",
    summary: "Given two independently sorted integer arrays, find the median of the combined sequence without merging them. Return a double representing the middle value (or average of the two middle values) of the hypothetical merged sorted array.",
    approach: "- Binary search on the shorter array to find a partition point such that the left halves of both arrays together contain exactly `(m+n)/2` elements.\n- At the correct partition, the largest element on any left side is no greater than the smallest element on any right side — this is the median invariant.\n- Handle the odd/even total-length cases: for odd, the median is the max of the two left-side boundary values; for even, it is the average of that max and the min of the two right-side boundary values.\n- Using `INT_MIN`/`INT_MAX` as sentinels for empty left/right edges keeps the comparison logic uniform and branch-free.",
    code: "#include <vector>\n#include <algorithm>\n#include <climits>\nusing namespace std;\n\nclass Solution {\npublic:\n    double findMedianSortedArrays(vector<int>& nums1, vector<int>& nums2) {\n        // Always binary-search the shorter array to keep the loop O(log(min(m,n))).\n        if (nums1.size() > nums2.size())\n            return findMedianSortedArrays(nums2, nums1);\n\n        int m = (int)nums1.size();\n        int n = (int)nums2.size();\n        int half = (m + n + 1) / 2; // left half size of the merged array\n\n        int lo = 0, hi = m;\n        while (lo <= hi) {\n            // i = number of elements taken from nums1's left partition\n            int i = lo + (hi - lo) / 2;\n            // j = remaining elements needed for the left half\n            int j = half - i;\n\n            // Boundary values; sentinels handle edge partitions gracefully.\n            int maxLeft1  = (i == 0) ? INT_MIN : nums1[i - 1];\n            int minRight1 = (i == m) ? INT_MAX : nums1[i];\n            int maxLeft2  = (j == 0) ? INT_MIN : nums2[j - 1];\n            int minRight2 = (j == n) ? INT_MAX : nums2[j];\n\n            if (maxLeft1 <= minRight2 && maxLeft2 <= minRight1) {\n                // Correct partition found.\n                int leftMax  = max(maxLeft1, maxLeft2);\n                int rightMin = min(minRight1, minRight2);\n                if ((m + n) % 2 == 1)\n                    return leftMax;          // odd total: median is the left-half max\n                return (leftMax + rightMin) / 2.0; // even total: average of middle two\n            } else if (maxLeft1 > minRight2) {\n                hi = i - 1; // nums1's left side is too large; move partition left\n            } else {\n                lo = i + 1; // nums2's left side is too large; move partition right\n            }\n        }\n        return 0.0; // unreachable for valid input\n    }\n};\n",
