    summary: "Given a string containing '(', ')', and '*' (which can act as '(', ')', or empty string), determine whether the string can represent a valid parenthesis sequence.",
    approach: "- Track a range `[lo, hi]` representing the minimum and maximum possible number of unmatched open parentheses at each step.\n- '(' increments both bounds; ')' decrements both; '*' widens the range by decrementing `lo` and incrementing `hi`.\n- If `hi` ever drops below zero, more ')' have appeared than any assignment of '*' can compensate — return false immediately.\n- Clamp `lo` to zero (we can never have a negative open count) and, after processing all characters, the string is valid iff `lo == 0`.",
    code: "#include <string>\nusing namespace std;\n\nclass Solution {\npublic:\n    bool checkValidString(string s) {\n        // lo = minimum possible open-paren count\n        // hi = maximum possible open-paren count\n        int lo = 0, hi = 0;\n\n        for (char c : s) {\n            if (c == '(') {\n                ++lo; ++hi;\n            } else if (c == ')') {\n                --lo; --hi;\n            } else {          // '*' can be '(', ')', or \"\"\n                --lo; ++hi;\n            }\n\n            // More ')' than any '*' assignment can fix\n            if (hi < 0) return false;\n\n            // Open count cannot go negative; clamp lo\n            if (lo < 0) lo = 0;\n        }\n\n        // Valid iff it is possible to have zero unmatched opens\n        return lo == 0;\n    }\n};\n",
    timeComplexity: "O(n)",
    spaceComplexity: "O(1)",
