    routeSlug: "98-validate-binary-search-tree",
    summary: "Given the root of a binary tree, determine whether it is a valid Binary Search Tree — meaning every node's value is strictly greater than all values in its left subtree and strictly less than all values in its right subtree, recursively throughout the entire tree.",
    approach: "- Propagate a valid **[min, max)** range down the tree during DFS: the root starts with an unbounded range, and each recursive call tightens the bounds.\n- When descending **left**, the current node's value becomes the new upper bound; when descending **right**, it becomes the new lower bound.\n- Using `long long` sentinel values (`LLONG_MIN` / `LLONG_MAX`) instead of pointer comparisons cleanly handles integer-range edge cases without extra nullity checks.\n- Every node is visited exactly once, so the approach is linear in the number of nodes.",
    code: "#include <climits>\nusing namespace std;\n\n// TreeNode definition assumed provided by the judge.\nstruct TreeNode {\n    int val;\n    TreeNode *left, *right;\n    TreeNode() : val(0), left(nullptr), right(nullptr) {}\n    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n    TreeNode(int x, TreeNode *l, TreeNode *r) : val(x), left(l), right(r) {}\n};\n\nclass Solution {\npublic:\n    bool isValidBST(TreeNode* root) {\n        return validate(root, LLONG_MIN, LLONG_MAX);\n    }\n\nprivate:\n    // Each node must satisfy: lo < node->val < hi\n    bool validate(TreeNode* node, long long lo, long long hi) {\n        if (!node) return true;\n        if (node->val <= lo || node->val >= hi) return false;\n        // Left subtree: values must be < node->val (tighten upper bound)\n        // Right subtree: values must be > node->val (tighten lower bound)\n        return validate(node->left,  lo,        node->val)\n            && validate(node->right, node->val, hi);\n    }\n};",
    timeComplexity: "O(n)",
    spaceComplexity: "O(h), where h is the tree height — O(log n) for a balanced tree, O(n) worst case for a skewed tree",
